<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Mini Desktop</title>
<style>
/* Basic reset */
body,html{margin:0;padding:0;height:100%;font-family:sans-serif;background:#222;color:#eee;}
#desktop{position:absolute;top:0;left:0;width:100%;height:100%;background:url('data:image/svg+xml,<svg xmlns="http://www.w3.org/2000/svg" width="400" height="400"><rect width="400" height="400" fill="%23222"/><circle cx="200" cy="200" r="150" fill="%23333"/></svg>') center/cover;}
#taskbar{position:absolute;bottom:0;width:100%;height:40px;background:#111;border-top:1px solid #444;display:flex;align-items:center;padding-left:10px;}
button{background:none;border:none;color:#eee;padding:5px 10px;margin-right:5px;cursor:pointer;}
button:hover{background:#333;}

.window{
  position:absolute;
  top:50px;left:50px;
  width:400px;height:300px;
  background:#222;
  border:1px solid #555;
  box-shadow:0 0 10px rgba(0,0,0,.5);
  display:none;
}
.window-header{
  height:30px;background:#111;display:flex;align-items:center;padding-left:5px;
  cursor:move;
}
.win-close{margin-left:auto;margin-right:5px;color:#f88;cursor:pointer;}
#files-window,#notepad-window{min-width:360px;min-height:240px;}

#files-path{padding:5px;background:#111;border-bottom:1px solid #444;font-family:monospace;}
.fs-item{padding:3px 10px;margin:2px 0;cursor:pointer;}
.fs-item:hover{background:#333;}
#files-up{margin:5px;color:#88f;cursor:pointer;}

.tab{
  display:inline-block;padding:5px 10px;background:#111;border-right:1px solid #444;
  cursor:pointer;
}
.tab.active{background:#222;color:#fff;}
#new-tab{display:inline-block;margin-left:5px;color:#8f8;cursor:pointer;}
textarea{width:100%;height:calc(100% - 30px);border:none;background:#111;color:#eee;font-family:monospace;padding:10px;box-sizing:border-box;}
</style>
</head>
<body>
<div id="desktop">
  <div id="taskbar">
    <button id="open-files">Files</button>
    <button id="open-notepad">Notepad</button>
  </div>

  <!-- Files Window -->
  <div id="files-window" class="window">
    <div class="window-header"><span>Files</span><span class="win-close">&times;</span></div>
    <div id="files-path">/</div>
    <div id="files-up">[Up]</div>
    <div id="file-list"></div>
  </div>

  <!-- Notepad Window -->
  <div id="notepad-window" class="window">
    <div class="window-header"><span>Notepad</span><span class="win-close">&times;</span></div>
    <div id="tabs"></div>
    <textarea id="editor"></textarea>
  </div>
</div>

<script>
// ---------- Filesystem ----------
const fs = {
  '/': {type:'dir', children:{bin:1, etc:1, home:1, usr:1, var:1}},
  '/home': {type:'dir', children:{user:1}},
  '/home/user': {type:'dir', children:{Documents:1, Downloads:1, Pictures:1}},
  '/home/user/Documents': {type:'dir', children:{}},
  '/home/user/Downloads': {type:'dir', children:{}},
  '/home/user/Pictures': {type:'dir', children:{}}
};
let currentPath = '/';
function renderFiles(){
  const list=document.getElementById('file-list');
  list.innerHTML='';
  const node=fs[currentPath];
  for(const name in node.children){
    const item=document.createElement('div');
    item.className='fs-item';
    item.textContent=name;
    item.dataset.name=name;
    if(fs[`${currentPath}${name}`] && fs[`${currentPath}${name}`].type==='dir'){
      item.addEventListener('dblclick',()=>{navigate(`${currentPath}${name}/`);});
    }
    list.appendChild(item);
  }
}
function navigate(path){
  currentPath=path;
  document.getElementById('files-path').textContent=currentPath;
  renderFiles();
}
document.getElementById('files-up').addEventListener('click',()=>{
  if(currentPath!=='/'){
    const parts=currentPath.split('/').filter(Boolean);
    parts.pop();
    navigate('/'+parts.join('/')+'/');
  }
});
renderFiles();

// ---------- Window handling ----------
function showWindow(id){
  document.querySelectorAll('.window').forEach(w=>w.style.display='none');
  document.getElementById(id).style.display='block';
}
document.getElementById('open-files').addEventListener('click',()=>showWindow('files-window'));
document.getElementById('open-notepad').addEventListener('click',()=>{showWindow('notepad-window');loadTabs();});
document.querySelectorAll('.win-close').forEach(btn=>{
  btn.addEventListener('click',()=>{
    btn.parentElement.parentElement.style.display='none';
  });
});

// ---------- Notepad ----------
let tabs=[];
function loadTabs(){
  const stored=localStorage.getItem('tabs');
  if(stored) tabs=JSON.parse(stored);
  else tabs=[{id:Date.now(),content:''}];
  renderTabs();
}
function saveTabs(){localStorage.setItem('tabs',JSON.stringify(tabs));}
function renderTabs(){
  const tabsDiv=document.getElementById('tabs');
  tabsDiv.innerHTML='';
  tabs.forEach(tab=>{
    const t=document.createElement('div');
    t.className='tab'+(tab.id===activeTab?.id?' active':'');
    t.textContent=tab.id;
    t.dataset.id=tab.id;
    t.addEventListener('click',()=>{switchTab(tab.id);});
    tabsDiv.appendChild(t);
  });
  const newBtn=document.createElement('div');newBtn.id='new-tab';newBtn.textContent='+';
  newBtn.addEventListener('click',createNewTab);
  tabsDiv.appendChild(newBtn);
}
let activeTab=null;
function switchTab(id){
  activeTab=tabs.find(t=>t.id==id);
  document.getElementById('editor').value=activeTab.content;
  renderTabs();
}
function createNewTab(){
  const newT={id:Date.now(),content:''};
  tabs.push(newT);
  switchTab(newT.id);
  saveTabs();
}
document.getElementById('editor').addEventListener('input',e=>{
  if(activeTab) activeTab.content=e.target.value;
});

// Initialize first tab
let activeTab=null;
loadTabs();

</script>
</body>
</html>
